// ─── v2-category-attributes ─────────────────────────────────────────
// Input: { platform: 'emag'|'trendyol'|'temu', categoryId: '123' }
// Output: { attributes: [{ id, name, type, required }] }
//
// CONFIGURARE:
//   Setează variabilele de mediu n8n:
//     EMAG_API_USER   = username-ul tău eMAG Marketplace
//     EMAG_API_KEY    = API key-ul tău eMAG Marketplace
//     TRENDYOL_SUPPLIER_ID = Supplier ID Trendyol
//     TRENDYOL_API_KEY    = API Key Trendyol
//     TRENDYOL_API_SECRET = API Secret Trendyol
// ─────────────────────────────────────────────────────────────────────

const body = $input.first().json.body || {};
const platform = (body.platform || 'emag').toLowerCase();
const categoryId = body.categoryId;

if (!categoryId) {
  return [{ json: { attributes: [], error: 'categoryId lipsă' } }];
}

let attributes = [];

try {
  if (platform === 'emag') {
    // ── eMAG Marketplace API ────────────────────────────────────────
    const emagUser = $env['EMAG_API_USER'] || '';
    const emagKey  = $env['EMAG_API_KEY']  || '';
    const authHeader = 'Basic ' + Buffer.from(`${emagUser}:${emagKey}`).toString('base64');

    // Fetch caracteristicile categoriei
    const data = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://marketplace.emag.ro/api-3/characteristic/read',
      headers: {
        'Authorization': authHeader,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: {
        filters: [
          { name: 'category_id', value: parseInt(categoryId) }
        ],
        count: 200,
        currentPage: 1
      },
      json: true
    });

    const results = data.results || [];
    attributes = results.map(attr => ({
      id: String(attr.id),
      name: attr.name || `Atribut ${attr.id}`,
      // type_id: 1=text, 2=select/radio, 3=number, 4=multiselect
      type: [2, 4].includes(attr.type_id) ? 'select' : 'text',
      required: attr.required === 1 || attr.required === true,
      values: (attr.values || []).map(v => ({ id: String(v.id), name: v.name }))
    }));

  } else if (platform === 'trendyol') {
    // ── Trendyol API ────────────────────────────────────────────────
    const supplierId = $env['TRENDYOL_SUPPLIER_ID'] || '';
    const apiKey    = $env['TRENDYOL_API_KEY']    || '';
    const apiSecret = $env['TRENDYOL_API_SECRET'] || '';
    const authHeader = 'Basic ' + Buffer.from(`${apiKey}:${apiSecret}`).toString('base64');

    const data = await $helpers.httpRequest({
      method: 'GET',
      url: `https://api.trendyol.com/sapigw/product/category-attributes/${categoryId}`,
      headers: {
        'Authorization': authHeader,
        'User-Agent': `${supplierId} - SelfIntegration`,
        'Accept': 'application/json'
      },
      json: true
    });

    const trendyolAttrs = data.categoryAttributes || [];
    attributes = trendyolAttrs.map(attr => ({
      id: String(attr.attribute?.id || attr.id),
      name: attr.attribute?.name || attr.name || `Atribut ${attr.id}`,
      type: (attr.attributeValues && attr.attributeValues.length > 0) ? 'select' : 'text',
      required: attr.required === true,
      values: (attr.attributeValues || []).map(v => ({ id: String(v.id), name: v.name }))
    }));

  } else if (platform === 'temu') {
    // ── Temu — API propriu / placeholder ───────────────────────────
    // Temu nu are API public standard. Adaptează după integrarea ta.
    attributes = [
      { id: 'temu_brand',       name: 'Brand',         type: 'text',   required: true,  values: [] },
      { id: 'temu_color',       name: 'Culoare',       type: 'select', required: false, values: [] },
      { id: 'temu_size',        name: 'Dimensiune',    type: 'select', required: false, values: [] },
      { id: 'temu_material',    name: 'Material',      type: 'text',   required: false, values: [] },
      { id: 'temu_description', name: 'Descriere',     type: 'text',   required: false, values: [] }
    ];
  }

} catch (err) {
  console.error(`[v2-category-attributes] Eroare pentru ${platform} / cat ${categoryId}:`, err.message);
  return [{ json: { attributes: [], error: err.message } }];
}

return [{ json: { attributes } }];
